"""Minimal annoy stub for NeMo Guardrails on Windows (no C++ build tools)."""


class AnnoyIndex:
    def __init__(self, f, metric="angular"):
        self.f = f
        self.metric = metric
        self._items = {}
        self._n_items = 0

    def add_item(self, i, vector):
        self._items[i] = list(vector)
        self._n_items = max(self._n_items, i + 1)

    def build(self, n_trees):
        pass

    def get_nns_by_vector(self, vector, n, include_distances=False):
        if not self._items:
            return ([], []) if include_distances else []

        import math

        def cosine_dist(a, b):
            dot = sum(x * y for x, y in zip(a, b))
            norm_a = math.sqrt(sum(x * x for x in a))
            norm_b = math.sqrt(sum(x * x for x in b))
            if norm_a == 0 or norm_b == 0:
                return 2.0
            return 1.0 - dot / (norm_a * norm_b)

        scored = []
        for idx, item_vec in self._items.items():
            dist = cosine_dist(vector, item_vec)
            scored.append((idx, dist))

        scored.sort(key=lambda x: x[1])
        top = scored[:n]

        if include_distances:
            return [x[0] for x in top], [x[1] for x in top]
        return [x[0] for x in top]

    def get_n_items(self):
        return self._n_items
